def getSum(a: int, b: int) -> int:
    mask    = 0xFFFFFFFF
    max_int = 0x7FFFFFFF
    while b & mask:
        carry = ((a & b) << 1) & mask
        a = (a ^ b) & mask
        b = carry
    # If high bit set, convert back to negative
    return a if a <= max_int else ~(a ^ mask)

