    const RED, BLUE = 0, 1
    type Edge struct{ to, color int }
    graph := make([][]Edge, n)
    for _, e := range redEdges {
        graph[e[0]] = append(graph[e[0]], Edge{e[1], RED})
    }
    for _, e := range blueEdges {
        graph[e[0]] = append(graph[e[0]], Edge{e[1], BLUE})
    }

    ans := make([]int, n)
    for i := range ans { ans[i] = -1 }
    ans[0] = 0

