    visited := map[State]bool{}
    type Item struct{ node, color, dist int }
    queue := []Item{{0, RED, 0}, {0, BLUE, 0}}
    visited[State{0, RED}] = true
    visited[State{0, BLUE}] = true

    for len(queue) > 0 {
        cur := queue[0]
        queue = queue[1:]
        nextColor := 1 - cur.color
        for _, e := range graph[cur.node] {
            if e.color == nextColor {
