                if !visited[s] {
                    visited[s] = true
                    if ans[e.to] == -1 {
                        ans[e.to] = cur.dist + 1
                    }
                    queue = append(queue, Item{e.to, e.color, cur.dist + 1})
                }
            }
        }
    }
    return ans
