def numberOfPowerfulInt(start: int, finish: int, limit: int, s: str) -> int:
    if any(int(c) > limit for c in s):
        return 0

    def count(n: int) -> int:
        t = str(n)
        n_len, s_len = len(t), len(s)
        if n_len < s_len:
            return 0
        total = 0
        # All powerful numbers with L digits where s_len <= L < n_len
        for L in range(s_len, n_len):
            pre = L - s_len
            if pre == 0:
                if s[0] != '0':
                    total += 1
            else:
                total += limit * (limit + 1) ** (pre - 1)
        # Exactly n_len digits
        pre = n_len - s_len
        if pre == 0:
            total += 1 if t >= s else 0
        else:
            tight = True
            for i in range(pre):
                lo = 1 if i == 0 else 0
                d = int(t[i])
                free_upper = d if d <= limit else limit + 1
                total += max(0, free_upper - lo) * (limit + 1) ** (pre - i - 1)
                if d > limit:
                    tight = False
                    break
            if tight and t[pre:] >= s:
                total += 1
        return total

    return count(finish) - count(start - 1)

