import "strconv"

func numberOfPowerfulInt(start int64, finish int64, limit int, s string) int64 {
    for _, c := range s {
        if int(c-'0') > limit {
            return 0
        }
    }
    pw := func(base, exp int) int64 {
        r := int64(1)
        for i := 0; i < exp; i++ {
            r *= int64(base)
        }
        return r
    }
    countUp := func(n int64) int64 {
        if n <= 0 {
            return 0
        }
        t := strconv.FormatInt(n, 10)
        nLen, sLen := len(t), len(s)
        if nLen < sLen {
            return 0
        }
        total := int64(0)
        for L := sLen; L < nLen; L++ {
            pre := L - sLen
            if pre == 0 {
                if s[0] != '0' {
                    total++
                }
            } else {
                total += int64(limit) * pw(limit+1, pre-1)
            }
        }
        pre := nLen - sLen
        if pre == 0 {
            if t >= s {
                total++
            }
        } else {
            tight := true
            for i := 0; i < pre; i++ {
                lo := 0
                if i == 0 {
                    lo = 1
                }
                d := int(t[i] - '0')
                freeUpper := d
                if d > limit {
                    freeUpper = limit + 1
                }
                if freeUpper-lo > 0 {
                    total += int64(freeUpper-lo) * pw(limit+1, pre-i-1)
                }
                if d > limit {
                    tight = false
                    break
                }
            }
            if tight && t[pre:] >= s {
                total++
            }
        }
        return total
    }
    return countUp(finish) - countUp(start-1)
}

