public long numberOfPowerfulInt(long start, long finish, int limit, String s) {
    for (char c : s.toCharArray())
        if (c - '0' > limit) return 0;
    return countUpTo(finish, limit, s) - countUpTo(start - 1, limit, s);
}

private long countUpTo(long n, int limit, String s) {
    if (n <= 0) return 0;
    String t = Long.toString(n);
    int nLen = t.length(), sLen = s.length();
    if (nLen < sLen) return 0;
    long total = 0;
    for (int L = sLen; L < nLen; L++) {
        int pre = L - sLen;
        if (pre == 0) {
            if (s.charAt(0) != '0') total++;
        } else {
            total += (long) limit * pow(limit + 1, pre - 1);
        }
    }
    int pre = nLen - sLen;
    if (pre == 0) {
        if (t.compareTo(s) >= 0) total++;
    } else {
        boolean tight = true;
        for (int i = 0; i < pre; i++) {
            int lo = (i == 0) ? 1 : 0;
            int d = t.charAt(i) - '0';
            int freeUpper = d <= limit ? d : limit + 1;
            if (freeUpper - lo > 0)
                total += (long)(freeUpper - lo) * pow(limit + 1, pre - i - 1);
            if (d > limit) { tight = false; break; }
        }
        if (tight && t.substring(pre).compareTo(s) >= 0) total++;
    }
    return total;
}

private long pow(int base, int exp) {
    long r = 1;
    for (int i = 0; i < exp; i++) r *= base;
    return r;
}

