        int[] cur = q.poll();
        for (int[] d : dirs) {
            int nr = cur[0]+d[0], nc = cur[1]+d[1];
            if (nr>=0 && nr<h.length && nc>=0 && nc<h[0].length && !vis[nr][nc] && h[nr][nc]>=h[cur[0]][cur[1]]) {
                vis[nr][nc] = true; q.offer(new int[]{nr,nc});
            }
        }
    }
