        if len(w1) > len(w2) && w1[:minLen] == w2[:minLen] { return "" }
        for j := 0; j < minLen; j++ {
            if w1[j] != w2[j] {
                adj[w1[j]] = append(adj[w1[j]], w2[j])
                inDegree[w2[j]]++
                break
            }
        }
    }
    queue := []byte{}
    for ch, deg := range inDegree { if deg == 0 { queue = append(queue, ch) } }
    var result []byte
