public String alienOrder(String[] words) {
    Map<Character, Set<Character>> adj = new HashMap<>();
    Map<Character, Integer> inDegree = new HashMap<>();
    for (String w : words) for (char ch : w.toCharArray()) inDegree.putIfAbsent(ch, 0);
    for (int i = 0; i < words.length - 1; i++) {
        String w1 = words[i], w2 = words[i+1];
        int minLen = Math.min(w1.length(), w2.length());
        if (w1.length() > w2.length() && w1.substring(0, minLen).equals(w2.substring(0, minLen))) return "";
        for (int j = 0; j < minLen; j++) {
            if (w1.charAt(j) != w2.charAt(j)) {
                adj.computeIfAbsent(w1.charAt(j), k -> new HashSet<>()).add(w2.charAt(j));
                inDegree.merge(w2.charAt(j), 1, Integer::sum);
                break;
            }
        }
    }
    Queue<Character> queue = new LinkedList<>();
    for (Map.Entry<Character,Integer> e : inDegree.entrySet()) if (e.getValue() == 0) queue.offer(e.getKey());
    StringBuilder result = new StringBuilder();
    while (!queue.isEmpty()) {
        char ch = queue.poll(); result.append(ch);
        if (adj.containsKey(ch)) for (char nb : adj.get(ch)) { inDegree.merge(nb, -1, Integer::sum); if (inDegree.get(nb) == 0) queue.offer(nb); }
    }
    return result.length() == inDegree.size() ? result.toString() : "";
}

