func maxProduct(nums []int) int {
    result := nums[0]
    curMin, curMax := 1, 1
    for _, num := range nums {
        if num == 0 {
            curMin, curMax = 1, 1
            if result < 0 { result = 0 }
            continue
        }
        tmp := curMax * num
        a, b, c := curMax*num, curMin*num, num
        if a > b { curMax = a } else { curMax = b }
        if curMax < c { curMax = c }
        if a < b { curMin = a } else { curMin = b }
        if curMin > c { curMin = c }
        _ = tmp
        if curMax > result { result = curMax }
    }
    return result
}

