    for (int num : nums) {
        if (num == 0) { curMin = curMax = 1; result = Math.max(result, 0); continue; }
        int tmp = curMax * num;
        curMax = Math.max(Math.max(curMax * num, curMin * num), num);
        curMin = Math.min(Math.min(tmp, curMin * num), num);
        result = Math.max(result, curMax);
    }
    return result;
}

